<template>
    <!-- 인트로 -->
    <main-intro @introState ="introState"></main-intro>

    <!-- 헤더 -->
    <main-header v-if="endIntro"></main-header>

    <!-- 메인 -->
    <router-view v-if="endIntro" v-slot="{ Component, route }">
        <Transition
            appear
            @before-enter="beforeEnter"
            @enter="enter"
            @after-enter="afterEnter"
            :css="false"
        >
            <main :key="route.name" class="main">
                <component :is="Component"></component>
            </main>
        </Transition>
    </router-view>

    <!-- 푸터 -->
    <main-footer v-if="endIntro"></main-footer>
</template>

<script>
import MainIntro from '@/components/Main-Intro.vue'
import MainHeader from '@/components/Main-Header.vue'
import MainFooter from '@/components/Main-Footer.vue'
import gsap from 'gsap'
export default {
    name: 'App',
    components: {
        MainIntro,
        MainHeader,
        MainFooter
    },
    data() {
        return{
            endIntro: false,
        }
    },
    methods: {
        introState(state){
            console.log("THE END", state);
            this.endIntro = state;
        }
    },
    setup(){
        const beforeEnter = (el) => {
            console.log('before enter');
            gsap.set(el, {
                y: -100,
                opacity: 0
            });
        }
        const enter = (el, done) => {
            console.log('enter');
            gsap.to(el, {
                delay: 0.5,
                duration: 1,
                y: 0,
                opacity: 1,
                onComplete: done
            });
        }
        const afterEnter = () => {
            console.log('after enter');
        }
        return{
            beforeEnter,
            enter,
            afterEnter
        }
    },
}
</script>

