<template>
    <div class="intro">
        <div class="intro__inner">
            <Transition appear @before-enter="beforeEnter" @enter="enter" :css="false">
                <div class="intro__logo">
                    <svg
                        v-for="i in 4"
                        v-bind:key="i"
                        :data-logo="i"
                        xmlns="http://www.w3.org/2000/svg"
                        viewBox="0 0 365 100"
                    >
                        <g>
                            <polygon class="w1" points="132.5 0 232.5 0 132.5 100 132.5 0" />
                            <polygon class="w2" points="182.5 0 132.5 50 132.5 100 232.5 0 182.5 0" />
                        </g>
                        <g>
                            <polygon class="s1" points="182.5 0 232.5 0 182.5 50 132.5 50 182.5 0" />
                            <polygon class="s2" points="182.5 50 232.5 50 182.5 100 132.5 100 182.5 50" />
                        </g>
                        <g>
                            <polygon class="m1" points="182.5 100 232.5 50 232.5 0 132.5 100 182.5 100" />
                            <polygon class="m2" points="232.5 100 132.5 100 232.5 0 232.5 100" />
                        </g>
                    </svg>
                </div>
            </Transition>
        </div>
    </div>
</template>

<script>
import gsap from 'gsap'
export default {
    setup(props, {emit}) {
        const introComplete = () => {
            emit('introState', true);
        }
        const t1 = gsap.timeline();
        const logo = {
            x: 85,
            y: 55,
            delay: 1.5,
            duration: 1,
            point: {
                w1: '0 0 100 0 0 100 0 0',
                w2: '105 0 55 50 55 100 155 0 105 0',
                s1: '180 0 230 0 177.5 52.5 127.5 52.5 180 0',
                s2: '187.5 47.5 237.5 47.5 185 100 135 100 187.5 47.5',
                m1: '260 100 310 50 310 0 210 100 260 100',
                m2: '365 100 265 100 365 0 365 100'
            }
        }
        const beforeEnter = (el) => {
            gsap.set(el, { opacity: 0 });
        }
        const enter = (el) => {
            t1.to(el, {
                opacity: 1,
                ease: 'expo',
                duration: 1,
                onComplete(){
                    gsap.to('.w1', { duration: 1, ease: 'expo', attr: { points: logo.point.w1 } });
                    gsap.to('.w2', { duration: 1, ease: 'expo', attr: { points: logo.point.w2 } });
                    gsap.to('.s1', { duration: 1, ease: 'expo', attr: { points: logo.point.s1 } });
                    gsap.to('.s2', { duration: 1, ease: 'expo', attr: { points: logo.point.s2 } });
                    gsap.to('.m1', { duration: 1, ease: 'expo', attr: { points: logo.point.m1 } });
                    gsap.to('.m2', { duration: 1, ease: 'expo', attr: { points: logo.point.m2 } });
                }
            });
            // Roll
            t1.to('[data-logo="1"]', { x: logo.x * 2, y: -logo.y * 2, delay: logo.delay, duration: logo.duration, ease: 'expo.inOut' }, '=-1');
            t1.to('[data-logo="2"]', { x: logo.x, y: -logo.y, duration: logo.duration, ease: 'expo.inOut' }, '=-'+ logo.duration +'');
            t1.to('[data-logo="4"]', { x: -logo.x, y: logo.y, duration: logo.duration, ease: 'expo.inOut' }, '=-'+ logo.duration +'');

            // Unroll
            t1.to('[data-logo="1"]', { x: 0, y: 0, delay: logo.delay, duration: 1, ease: 'expo' }, '=-0.5');
            t1.to('[data-logo="2"]', { x: 0, y: 0, duration: 1, ease: 'expo' }, '=-1');
            t1.to('[data-logo="4"]', { x: 0, y: 0, duration: 1, ease: 'expo' }, '=-1');

            // Squeeze
            // t1.to('.intro__logo', {
            //     top: 'calc(-50vh + 118px)',
            //     left: 'calc(-50vw + 165px)',
            //     maxWidth: 130,
            //     duration: 1,
            //     delay: 0.5,
            //     ease: 'expo',
            //     onStart(){
            //         gsap.to('[data-logo="2"]', { opacity: 0 });
            //         gsap.to('[data-logo="3"]', { opacity: 0 });
            //         gsap.to('[data-logo="4"]', { opacity: 0 });
            //     }
            // }, '=-0.5');

            // The End
            t1.to('[data-logo]', {
                onComplete(){
                    introComplete();
                }
            });
        }
        return {
            beforeEnter,
            enter
        }
    },
}
</script>

<style lang="scss" scoped>
.intro{
    z-index: 101;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: $color_background;

    &__inner{
        display: flex;
        align-items: center;
        justify-content: center;
        width: 100%;
        height: 100%;
    }
    &__logo{
        position: relative;
        max-width: 1200px;
        width: 80vw;
    }
    &__logo [data-logo]{
        display: block;
        position: relative;
        z-index: 4;
        width: 100%;
        height: 100%;
        fill: $color_primary;
    }
    &__logo [data-logo]:not(:first-child){
        position: absolute;
        top: 0;
        left: 0;
    }
    &__logo [data-logo="2"]{
        z-index: 3;
        fill: $color_pink;
    }
    &__logo [data-logo="3"]{
        z-index: 2;
        fill: $color_peach;
    }
    &__logo [data-logo="4"]{
        z-index: 1;
        fill: $color_apricot;
    }
}
</style>
